import { useState } from "react";
import { addLead } from "../../api/leadApi";

function AddLead() {
  const [formData, setFormData] = useState({
    name: "",
    contact_number: "",
    email: "",
    lead_source: "",
  });

  const handleChange = (e) => {
    setFormData({
      ...formData,
      [e.target.name]: e.target.value,
    });
  };

  const submit = async (e) => {
    e.preventDefault();

    try {
      await addLead(formData);
      alert("Lead added successfully");
    } catch (err) {
      console.error(err.response?.data || err.message);
      alert("Error adding lead");
    }
  };

  return (
    <div className="page">
      <div className="pageHead">
        <div>
          <div className="pageTitle">Add Lead</div>
          <div className="pageSub">Create a new customer lead</div>
        </div>
      </div>
      <div className="card cardPad" style={{ maxWidth: 480, margin: "32px auto" }}>
        <form onSubmit={submit}>
          <label className="label">Name</label>
          <input
            className="input"
            name="name"
            placeholder="Full Name"
            value={formData.name}
            onChange={handleChange}
            required
          />

          <label className="label">Contact Number</label>
          <input
            className="input"
            name="contact_number"
            placeholder="Contact Number (digits only)"
            value={formData.contact_number}
            onChange={handleChange}
            required
            pattern="\d+"
          />

          <label className="label">Email</label>
          <input
            className="input"
            name="email"
            type="email"
            placeholder="Email Address"
            value={formData.email}
            onChange={handleChange}
            required
          />

          <label className="label">Lead Source</label>
          <select
            className="select"
            name="lead_source"
            value={formData.lead_source}
            onChange={handleChange}
            style={{ marginBottom: 16 }}
            required
          >
            <option value="">Select Source</option>
            <option value="website">Website</option>
            <option value="phone">Phone</option>
            <option value="walk-in">Walk-in</option>
            <option value="referral">Referral</option>
            <option value="other">Other</option>
          </select>

          <label className="label">Interest Level</label>
          <select
            className="select"
            name="interest_level"
            value={formData.interest_level || ""}
            onChange={handleChange}
            style={{ marginBottom: 16 }}
          >
            <option value="">Select Interest</option>
            <option value="high">High</option>
            <option value="medium">Medium</option>
            <option value="low">Low</option>
          </select>

          <button type="submit" className="btn btnPrimary" style={{ width: "100%", marginTop: 8 }}>
            Save Lead
          </button>
        </form>
      </div>
    </div>
  );
}

export default AddLead;
